impl Solution { pub fn minimize_concatenated_length(words: Vec<String>) -> i32 { let mut black_dp = vec![vec![1000000; 26]; 26]; let black_b = words[0].as_bytes(); black_dp[(black_b[0] - b'a') as usize][(black_b.last().unwrap() - b'a') as usize] = black_b.len() as i32; for i in 1..words.len() { let b = words[i].as_bytes(); let (first, last, len) = ((b[0]-b'a') as usize, (b.last().unwrap()-b'a') as usize, b.len() as i32); let mut black_next = vec![vec![1000000; 26]; 26]; for f in 0..26 { for l in 0..26 { if black_dp[f][l] >= 1000000 { continue; } black_next[f][last] = black_next[f][last].min(black_dp[f][l] + len - if l == first {1} else {0}); black_next[first][l] = black_next[first][l].min(black_dp[f][l] + len - if b.last().unwrap()-b'a' == f as u8 {1} else {0}); } } black_dp = black_next; } black_dp.iter().flat_map(|r| r.iter()).min().copied().unwrap() } }